<template>
  <div id='app'>
    <v-toolbar
      flat
      color='transparent'
    >
      <v-menu
        fixed
        class='hidden-md-and-up'
      >
        <v-toolbar-side-icon slot='activator'></v-toolbar-side-icon>
        <v-list>
          <v-list-tile
            v-for='item in menu'
            :key='item.to'
            :to='item.to'
          >
            <v-list-tile-title>{{ item.title }}</v-list-tile-title>
          </v-list-tile>
        </v-list>
        <v-container grid-list-md>
          <v-layout row>
            <v-flex
              xs4
              v-for='item in social'
              :key='item.icon'
            >
              <v-btn
                icon
                v-bind:href='item.href'
              >
                <img
                  class='socialIcon'
                  v-bind:src='item.src'
                />
              </v-btn>
            </v-flex>
          </v-layout>
        </v-container>
      </v-menu>

      <v-toolbar-title>Isaac Phua</v-toolbar-title>

      <v-spacer></v-spacer>

      <v-toolbar-items class='hidden-sm-and-down'>
        <v-btn
          flat
          active-class=''
          v-for='item in menu'
          :key='item.to'
          :to='item.to'
        >
          {{ item.title }}
        </v-btn>
        <v-btn
          icon
          v-for='item in social'
          :key='item.icon'
          :href='item.href'
          target='_blank'
        >
          <img
            class='socialIcon'
            v-bind:src='item.src'
          />
        </v-btn>
      </v-toolbar-items>
    </v-toolbar>
    <transition
      name='slide-fade'
      mode='out-in'
    >
      <router-view />
    </transition>
  </div>
</template>

<script>
export default {
  name: 'app',
  data: function () {
    return {
      menu: [{ to: '/', title: 'Home' }, { to: '/about', title: 'About' }],
      social: [
        {
          icon: 'linkedin',
          href: 'https://www.linkedin.com/in/vei-wang-isaac-phua-bb0143129/',
          src: require('./assets/fonts/Black/Linkedin.svg')
        },
        {
          icon: 'github',
          href: 'https://github.com/Isaaafc',
          src: require('./assets/fonts/Black/GitHub.svg')
        },
        {
          icon: 'email',
          href: 'mailto:isaaafc@gmail.com',
          src: require('./assets/fonts/Black/Envelope-1.svg')
        }
      ]
    }
  }
}
</script>

<style>
#app {
  font-family: 'Roboto,sans-serif';
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  text-align: center;
  color: #2c3e50;
  margin-top: 60px;
  font-size: 1.2em;
}
.socialIcon {
  height: 15px;
  width: 15px;
}
.v-toolbar__title {
  font-weight: bold;
}
/* Enter and leave animations can use different */
/* durations and timing functions.              */
.slide-fade-enter-active {
  transition: all 0.3s ease;
}
.slide-fade-leave-active {
  transition: all 0.1s cubic-bezier(1, 0.5, 0.8, 1);
}
.slide-fade-enter, .slide-fade-leave-to
    /* .slide-fade-leave-active below version 2.1.8 */ {
  transform: translateX(10px);
  opacity: 0;
}
</style>



